import Home from "../pages/home/Home";
import Settings from "../pages/settings/Settings";
import Categories from "../pages/categories/Categories";
import Wallet from "../pages/wallet/Wallet";


export const routes = [

    {
        path: '/',
        element: <Home />
    },
    {
        path: 'home',
        element: <Home />
    },
    {
        path: 'settings',
        element: <Settings />
    },
    {
        path: 'categories',
        element: <Categories />
    },
    {
        path: 'walled',
        element: <Wallet />
    }

]
